+    #[test]
+    fn email_config_clone_independence() {
+        let original = EmailNotifyConfig {
+            enabled: true,
+            smtp_host: "smtp.example.com".to_string(),
+            smtp_port: 587,
+            from: "sender@example.com".to_string(),
+            to: vec!["a@example.com".to_string()],
